"use strict";(globalThis.webpackChunkself_healing_nixos_infra=globalThis.webpackChunkself_healing_nixos_infra||[]).push([[439],{5990(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/self-healing-nixos-infra/","label":"Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/architecture","label":"Architecture Overview","docId":"architecture","unlisted":false},{"type":"category","label":"Bootstrap & Filesystem","items":[{"type":"link","href":"/self-healing-nixos-infra/bootstrap-nixos-anywhere","label":"Bootstrap with nixos-anywhere","docId":"bootstrap-nixos-anywhere","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/btrfs-layout","label":"Btrfs Subvolume Layout","docId":"btrfs-layout","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/btrfs-snapshots","label":"Btrfs Snapshots & Snapper","docId":"btrfs-snapshots","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"AI Infrastructure Management","items":[{"type":"link","href":"/self-healing-nixos-infra/install-openclaw","label":"Install OpenClaw","docId":"install-openclaw","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/ai-managed-infra","label":"AI-Managed Infrastructure","docId":"ai-managed-infra","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Security & Recovery","items":[{"type":"link","href":"/self-healing-nixos-infra/totp-sudo-protection","label":"TOTP Sudo Protection","docId":"totp-sudo-protection","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/database-snapshot-strategy","label":"Database Snapshot Strategy","docId":"database-snapshot-strategy","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/disaster-recovery","label":"Disaster Recovery","docId":"disaster-recovery","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/ai-safety-and-rollback","label":"AI Safety & Rollback","docId":"ai-safety-and-rollback","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"ai-managed-infra":{"id":"ai-managed-infra","title":"AI-Managed Infrastructure","description":"With OpenClaw installed, this chapter defines the operational model: what the AI manages autonomously, what requires human approval, and how the entire change pipeline works.","sidebar":"tutorialSidebar"},"ai-safety-and-rollback":{"id":"ai-safety-and-rollback","title":"AI Safety & Rollback","description":"This final chapter defines the operating procedures for running AI-managed infrastructure safely. It covers guardrails, rollback workflows, failure budgets, and the principles that keep humans in control while benefiting from AI automation.","sidebar":"tutorialSidebar"},"architecture":{"id":"architecture","title":"Architecture Overview","description":"This page describes the full system architecture, component interactions, data flows, and failure handling strategies.","sidebar":"tutorialSidebar"},"bootstrap-nixos-anywhere":{"id":"bootstrap-nixos-anywhere","title":"Bootstrap with nixos-anywhere","description":"nixos-anywhere lets you install NixOS on any Linux server with root SSH access \u2014 no ISO image, no console access, no provider-specific tooling. It works by kexec-ing into a NixOS installer in RAM, partitioning the disk, and installing your declared configuration.","sidebar":"tutorialSidebar"},"btrfs-layout":{"id":"btrfs-layout","title":"Btrfs Subvolume Layout","description":"A well-designed subvolume layout is the foundation of a rollback-capable system. Each subvolume can be independently snapshotted, mounted with different options, and excluded from rollbacks when persistence is needed.","sidebar":"tutorialSidebar"},"btrfs-snapshots":{"id":"btrfs-snapshots","title":"Btrfs Snapshots & Snapper","description":"Snapshots are the core of the rollback strategy. This chapter covers manual snapshots, automated management with Snapper, and pre-rebuild hooks that ensure every system change has a restore point.","sidebar":"tutorialSidebar"},"database-snapshot-strategy":{"id":"database-snapshot-strategy","title":"Database Snapshot Strategy","description":"Databases require special snapshot handling. A naive filesystem snapshot of a running database can capture an inconsistent state \u2014 half-written transactions, dirty buffers, incomplete WAL entries. This chapter covers strategies for consistent database snapshots on Btrfs.","sidebar":"tutorialSidebar"},"disaster-recovery":{"id":"disaster-recovery","title":"Disaster Recovery","description":"This chapter is the runbook. It covers every major failure scenario, the detection method, and step-by-step recovery procedures. Print this page and keep it accessible \u2014 you\'ll need it when things go wrong.","sidebar":"tutorialSidebar"},"install-openclaw":{"id":"install-openclaw","title":"Install OpenClaw","description":"OpenClaw is an AI-powered infrastructure operator. It monitors system health, proposes configuration changes, and can execute approved operations \u2014 all within a policy-defined boundary. Think of it as an AI SRE agent that works alongside your existing NixOS tooling.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"This tutorial walks you through building a production-grade, self-healing server that combines declarative system management, copy-on-write snapshots, AI-assisted operations, and TOTP-protected critical commands.","sidebar":"tutorialSidebar"},"totp-sudo-protection":{"id":"totp-sudo-protection","title":"TOTP Sudo Protection","description":"This chapter configures TOTP (Time-based One-Time Password) authentication for sudo, ensuring that critical operations like nixos-rebuild switch require a 6-digit code from an authenticator app \u2014 even if an attacker gains shell access.","sidebar":"tutorialSidebar"}}}}')}}]);